#!/usr/bin/env bash
# ╔═══════════════════════════════════════════════════════════════════╗
# ║   HOMURA  ·  Chronos Download Manager  ·  v1.0.0                 ║
# ║   Self-contained launcher  ·  by wexloom                         ║
# ╠═══════════════════════════════════════════════════════════════════╣
# ║   Usage:   chmod +x homura_dl.sh  &&  ./homura_dl.sh             ║
# ║   Distros: Arch  ·  Ubuntu/Debian  ·  Fedora/RHEL                ║
# ║   Run as your NORMAL USER — do NOT run with sudo                 ║
# ╚═══════════════════════════════════════════════════════════════════╝
#
# ═══════════════════════════════════════════════════════════════════
# DEPENDENCIES
# ═══════════════════════════════════════════════════════════════════
#   python3       - Runtime for the GUI app
#   tkinter       - Python GUI toolkit (usually separate package)
#   yt-dlp        - Media downloader (YouTube, Twitch, TikTok, 1000+ sites)
#   ffmpeg        - Required for HD video+audio merging via yt-dlp
#
# INSTALL (Arch):
#   sudo pacman -S python tk yt-dlp ffmpeg
#
# INSTALL (Debian/Ubuntu):
#   sudo apt install python3 python3-tk yt-dlp ffmpeg
#
# INSTALL (Fedora/RHEL):
#   sudo dnf install python3 python3-tkinter yt-dlp ffmpeg
#
# NOTE: The script will auto-detect and install missing deps on first run.
#       Do NOT run with sudo — it will auto-request sudo when needed.
#
# ═══════════════════════════════════════════════════════════════════
# SETUP
# ═══════════════════════════════════════════════════════════════════
#   chmod +x /home/kyoro/Pictures/icons/scripts/homuradm.sh
#
# ═══════════════════════════════════════════════════════════════════
# DESKTOP ENTRY  (~/.local/share/applications/dmhomura.desktop)
# ═══════════════════════════════════════════════════════════════════
#   [Desktop Entry]
#   Type=Application
#   Name=dmhomura
#   Comment=Launch my custom script
#   Exec=/home/kyoro/Pictures/icons/scripts/homuradm.sh
#   Icon=/home/kyoro/Pictures/icons/1.png
#   Terminal=true
#   Categories=Utility;
#
# ═══════════════════════════════════════════════════════════════════
# FEATURES
# ═══════════════════════════════════════════════════════════════════
#   Tab 1 — Chronos Download Manager  (direct HTTP/HTTPS downloads)
#   Tab 2 — yt-dlp GUI
#             · Quality presets       · Audio extraction
#             · Subtitle download     · Playlist support
#             · SponsorBlock          · Thumbnails & metadata
#             · Cookie support        · Proxy support
# ═══════════════════════════════════════════════════════════════════
# Includes:
#   Tab 1 — Chronos Download Manager  (direct HTTP/HTTPS)
#   Tab 2 — yt-dlp GUI  (YouTube, Twitch, Twitter/X, TikTok, 1000+ sites)
#            Quality presets · audio extract · subtitles · playlists
#            SponsorBlock · thumbnails · metadata · cookies · proxy

set -euo pipefail

R='\033[0;31m' G='\033[0;32m' Y='\033[1;33m'
P='\033[0;35m' C='\033[0;36m' W='\033[1;37m' D='\033[2m' X='\033[0m'

info() { echo -e "${C}  ◈  ${X}$*"; }
ok()   { echo -e "${G}  ✓  ${X}$*"; }
warn() { echo -e "${Y}  ⚠  ${X}$*"; }
err()  { echo -e "${R}  ✗  ${X}$*" >&2; }
die()  { err "$*"; exit 1; }
sep()  { echo -e "${P}  ────────────────────────────────────────────${X}"; }

clear
echo
echo -e "${P}  ██╗  ██╗ ██████╗ ███╗   ███╗██╗   ██╗██████╗  █████╗${X}"
echo -e "${P}  ██║  ██║██╔═══██╗████╗ ████║██║   ██║██╔══██╗██╔══██╗${X}"
echo -e "${W}  ███████║██║   ██║██╔████╔██║██║   ██║██████╔╝███████║${X}"
echo -e "${P}  ██╔══██║██║   ██║██║╚██╔╝██║██║   ██║██╔══██╗██╔══██║${X}"
echo -e "${P}  ██║  ██║╚██████╔╝██║ ╚═╝ ██║╚██████╔╝██║  ██║██║  ██║${X}"
echo -e "${P}  ╚═╝  ╚═╝ ╚═════╝ ╚═╝     ╚═╝ ╚═════╝ ╚═╝  ╚═╝╚═╝  ╚═╝${X}"
echo
echo -e "  ${C}炎  Chronos Download Manager + yt-dlp GUI  v1.0.0${X}   ${D}by wexloom${X}"
sep; echo

[[ $EUID -eq 0 ]] && die "Do not run as root. Run as your normal user."

detect_distro() {
    command -v pacman &>/dev/null && { echo "arch";   return; }
    command -v apt    &>/dev/null && { echo "debian"; return; }
    command -v dnf    &>/dev/null && { echo "fedora"; return; }
    command -v yum    &>/dev/null && { echo "rhel";   return; }
    echo "unknown"
}
DISTRO=$(detect_distro)
info "Distro: ${W}${DISTRO}${X}"; echo

install_pkg() {
    case "$DISTRO" in
        arch)   sudo pacman -S --needed --noconfirm "$1" ;;
        debian) sudo apt-get install -y "$2" ;;
        fedora) sudo dnf install -y "$3" ;;
        rhel)   sudo yum install -y "$3" ;;
        *)      warn "Unknown distro — install ${W}$1${X} manually"; return 1 ;;
    esac
}

# ── Check core deps ─────────────────────────────────────────────────────────
NEED=0
if command -v python3 &>/dev/null; then ok "python3"
else warn "python3 not found"; NEED=1; fi

if python3 -c "import tkinter" &>/dev/null 2>&1; then ok "tkinter"
else warn "tkinter not found"; NEED=1; fi

# yt-dlp check (optional but shown)
if command -v yt-dlp &>/dev/null; then
    YTDLP_VER=$(yt-dlp --version 2>/dev/null || echo "?")
    ok "yt-dlp  ${D}(${YTDLP_VER})${X}"
else
    warn "yt-dlp not found  ${D}(Media tab will offer to install it)${X}"
fi

# ffmpeg check (needed for yt-dlp merging)
if command -v ffmpeg &>/dev/null; then ok "ffmpeg"
else warn "ffmpeg not found  ${D}(needed for HD video+audio merging)${X}"; fi

echo

# ── Install missing core deps ────────────────────────────────────────────────
if [[ $NEED -eq 1 ]]; then
    sep; info "Installing missing packages..."; sep; echo
    command -v sudo &>/dev/null || die "sudo not found. Install it as root first."
    info "Requesting sudo..."; sudo -v || die "sudo auth failed."; ok "sudo cached."; echo

    if ! command -v python3 &>/dev/null; then
        info "Installing python3..."
        install_pkg "python" "python3" "python3" &>/dev/null && ok "python3" || warn "python3 install failed"
    fi

    if ! python3 -c "import tkinter" &>/dev/null 2>&1; then
        info "Installing tkinter..."
        case "$DISTRO" in
            arch)   sudo pacman -S --needed --noconfirm tk &>/dev/null ;;
            debian) sudo apt-get install -y python3-tk &>/dev/null ;;
            fedora) sudo dnf install -y python3-tkinter &>/dev/null ;;
            rhel)   sudo yum install -y python3-tkinter &>/dev/null ;;
        esac
        python3 -c "import tkinter" &>/dev/null 2>&1 && ok "tkinter" || \
            die "tkinter install failed.\nArch: sudo pacman -S tk\nUbuntu: sudo apt install python3-tk"
    fi
fi

# ── Offer yt-dlp install if missing ─────────────────────────────────────────
if ! command -v yt-dlp &>/dev/null; then
    echo
    sep
    echo -e "  ${Y}yt-dlp is not installed.${X}"
    echo -e "  It is required for the  ${W}Media (yt-dlp)${X}  tab."
    echo -e "  Supports: YouTube · Twitch · Twitter/X · TikTok · SoundCloud · 1000+ sites"
    echo
    read -r -p "  Install yt-dlp now? (Y/n): " ans
    if [[ "${ans,,}" != "n" ]]; then
        info "Installing yt-dlp..."
        if pip install --user yt-dlp &>/dev/null 2>&1; then
            ok "yt-dlp installed via pip"
        elif command -v sudo &>/dev/null; then
            case "$DISTRO" in
                arch)   sudo pacman -S --needed --noconfirm yt-dlp &>/dev/null && ok "yt-dlp (pacman)" ;;
                debian) sudo apt-get install -y yt-dlp &>/dev/null && ok "yt-dlp (apt)" ;;
                fedora) sudo dnf install -y yt-dlp &>/dev/null && ok "yt-dlp (dnf)" ;;
                *)      warn "Could not install yt-dlp automatically." ;;
            esac
        fi
    else
        warn "Skipping yt-dlp — Media tab will be limited."
    fi
fi

# ── Offer ffmpeg install if missing ─────────────────────────────────────────
if ! command -v ffmpeg &>/dev/null; then
    echo
    read -r -p "  Install ffmpeg? (needed for HD merging) (Y/n): " ans
    if [[ "${ans,,}" != "n" ]]; then
        info "Installing ffmpeg..."
        case "$DISTRO" in
            arch)   sudo pacman -S --needed --noconfirm ffmpeg &>/dev/null && ok "ffmpeg" ;;
            debian) sudo apt-get install -y ffmpeg &>/dev/null && ok "ffmpeg" ;;
            fedora) sudo dnf install -y ffmpeg &>/dev/null && ok "ffmpeg" ;;
            *)      warn "Install ffmpeg manually from https://ffmpeg.org" ;;
        esac
    fi
fi

ok "Dependency check complete."; sep; echo

# ── Display check ────────────────────────────────────────────────────────────
sep; info "Checking display..."; sep

if [[ -n "${DISPLAY:-}" ]]; then   ok "X11: ${DISPLAY}"
elif [[ -n "${WAYLAND_DISPLAY:-}" ]]; then ok "Wayland: ${WAYLAND_DISPLAY}"
else
    warn "No display detected."
    read -r -p "  Continue anyway? (y/N): " ans
    [[ "${ans,,}" == "y" ]] || die "Aborted."
fi

if [[ -n "${SSH_CLIENT:-}" || -n "${SSH_TTY:-}" ]]; then
    [[ -z "${DISPLAY:-}" ]] && die "SSH without X forwarding.\nUse: ssh -X user@host"
fi

echo; sep

# ── Extract ──────────────────────────────────────────────────────────────────
TMPDIR_APP=$(mktemp -d /tmp/homura_dl_XXXXXX)
APP_PATH="$TMPDIR_APP/homura_dl.py"

cleanup() { rm -rf "${TMPDIR_APP:-}" 2>/dev/null; }
trap cleanup EXIT INT TERM

info "Extracting application..."

python3 - "$APP_PATH" << 'DECODE_EOF'
import base64, sys
data = """"""
with open(sys.argv[1], 'wb') as f:
    f.write(base64.b64decode(data))
DECODE_EOF

chmod +x "$APP_PATH"
ok "Extracted: $APP_PATH"; echo; sep
echo -e "\n  ${P}炎  Launching HOMURA Chronos...${X}\n"
sleep 0.3

python3 "$APP_PATH"
